-- Templates : message de l'humain À LA souris du contact, pour son anniversaire
-- animal_type = 'souris' | animal_direction = 'to' | occasion = 'birthday'

insert into public.message_templates
  (user_id, title, content, tone, is_system, is_manual_only, occasion, animal_type, animal_direction)
values

(null, 'Joyeux anniversaire petite(e) étoile blanche.',
$$"Joyeux anniversaire petite(e) étoile blanche." Ton humain m'a envoyé une photo de toi ce matin. T'étais assis(e) sur son épaule. Toute blanche sur son pull noir. Comme un flocon de neige qui aurait choisi de rester. C'était la plus belle photo que j'ai reçue depuis longtemps. Joyeux anniversaire, contraste vivant et magnifique.
Avec photo sauvegardée en fond d'écran depuis ce matin, Ton fan photographique numéro un 🤍$$,
'humorous', true, false, 'birthday', 'souris', 'to'),

(null, 'Je t''avoue que j''avais des a priori sur les souris.',
$$"Je t'avoue que j'avais des a priori sur les souris." Le mot "souris" m'évoquait des choses. Des films. Des pièges. Des cris dans des cuisines. Et puis ton humain m'a montré comment tu grimpais sur son bras. Comment tu venais renifler son oreille. Comment tu t'endormais dans sa poche de chemise. Joyeux anniversaire, être qui détruit les préjugés un humain à la fois.
Avec préjugés définitivement et joyeusement abandonnés, Celui/celle que t'as converti(e) sans effort 🔄$$,
'humorous', true, false, 'birthday', 'souris', 'to'),

(null, 'Tes yeux rouges m''ont d''abord surpris(e).',
$$"Tes yeux rouges m'ont d'abord surpris(e)." Puis ton humain m'a dit que c'était juste de la mélanine. Que c'était beau. Que ça te donnait un regard unique. Et maintenant je trouve ça magnifique. Ce regard rouge sur du blanc immaculé. Comme deux rubis sertis dans de la nacre. Joyeux anniversaire, joyau vivant mal compris du grand public.
Avec perception définitivement transformée, Celui/celle qui trouve tes yeux rouges absolument beaux maintenant 💎$$,
'humorous', true, false, 'birthday', 'souris', 'to'),

(null, 'Ton humain t''a construit un labyrinthe pour ton anniversaire.',
$$"Ton humain t'a construit un labyrinthe pour ton anniversaire." Trois heures de construction. Carton. Tunnels. Bifurcations. Une récompense au centre. T'as trouvé le chemin en quarante secondes. T'as mangé la récompense. T'es reparti(e). Ton humain a regardé son œuvre en silence. Joyeux anniversaire, génie logique au sens du timing parfait.
Avec compassion pour l'architecte et admiration pour la navigatrice, Le/la témoin de ta victoire éclair 🏆$$,
'humorous', true, false, 'birthday', 'souris', 'to'),

(null, 'Je t''ai tendu le doigt la dernière fois.',
$$"Je t'ai tendu le doigt la dernière fois." Ton humain m'avait dit d'approcher doucement. De pas faire de mouvement brusque. De laisser faire. T'as reniflé. T'as tourné autour. T'as reniflé encore. Puis t'as grimpé sur ma main comme si t'avais décidé que j'étais acceptable. C'était le plus beau bulletin de notes de ma vie. Joyeux anniversaire, examinatrice au jugement définitif.
Avec mention très bien chérie pour toujours, Celui/celle qui a passé ton test avec fierté ✅$$,
'humorous', true, false, 'birthday', 'souris', 'to'),

(null, 'Ton humain t''appelle par ton prénom avec une intonation particulière.',
$$"Ton humain t'appelle par ton prénom avec une intonation particulière." Douce. Montante. Répétée. Et toi tu réagis. Tu lèves la tête. Tu cherches la voix. T'as appris ton prénom. T'as appris sa voix. T'as appris que les deux ensemble ça voulait dire quelque chose de bien. Joyeux anniversaire, être linguistique plus développé(e) que tout ce qu'on imagine.
Avec émerveillement sincère pour tes capacités, Celui/celle qui sous-estimait les souris et qui le regrette 🔤$$,
'humorous', true, false, 'birthday', 'souris', 'to'),

(null, 'Ton humain garde une poche libre dans sa chemise pour toi.',
$$"Ton humain garde une poche libre dans sa chemise pour toi." Systématiquement. Consciemment. Comme on garde une place dans une voiture pour un ami. Comme on réserve un siège à table. Cette poche c'est ta place dans sa vie. Concrète. Textile. Réservée. Joyeux anniversaire, passager(ère) permanent(e) de la vie de quelqu'un.
Avec émotion pour ce geste simple et immense, Celui/celle qui a remarqué la poche toujours libre 👕$$,
'humorous', true, false, 'birthday', 'souris', 'to'),

(null, 'Je t''ai apporté des graines spéciales pour ton anniversaire.',
$$"Je t'ai apporté des graines spéciales pour ton anniversaire." Ton humain m'a donné une liste. Précise. Avec des choses à éviter. Des préférences connues. Des textures appréciées. J'ai suivi la liste à la lettre. T'as tout reniflé méthodiquement. T'as commencé par ta chose préférée. J'avais bien travaillé. Joyeux anniversaire, gourmet(te) à la liste de préférences bien tenue.
Avec devoir accompli et satisfaction du travail bien fait, Ton fournisseur de graines agréé après briefing complet 🌱$$,
'humorous', true, false, 'birthday', 'souris', 'to'),

(null, 'Je sais pas comment t''es aussi rapide.',
$$"Je sais pas comment t'es aussi rapide." T'es minuscule. T'as des toutes petites pattes. Et pourtant quand tu décides d'aller quelque part t'es déjà là-bas avant qu'on ait compris que tu partais. Ton humain dit que c'est normal. Moi je trouve ça surnaturel. Joyeux anniversaire, être à la vitesse inversement proportionnelle à la taille.
Avec admiration pour ta physique défiant les lois du bon sens, Celui/celle qui t'a perdu(e) des yeux en une demi-seconde ⚡$$,
'humorous', true, false, 'birthday', 'souris', 'to'),

(null, 'Je comprends maintenant pourquoi ton humain t''aime comme ça.',
$$"Je comprends maintenant pourquoi ton humain t'aime comme ça." T'es petite mais présente. Silencieuse mais vivante. Fragile mais courageuse. Différente mais parfaite. T'es exactement ce dont certains humains ont besoin sans le savoir. Un être qui tient dans une main et qui remplit un cœur entier. Joyeux anniversaire, grande âme en tout petit corps.
Avec compréhension tardive et totalement sincère, Celui/celle que t'as convaincu(e) que la taille ne compte pas 🤍$$,
'humorous', true, false, 'birthday', 'souris', 'to');
